//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageglobalaccelerator_testimport(	"context"	"fmt"	"testing"	"github.com/aws/aws-sdk-go/service/globalaccelerator"	sdkacctest"github.com/hashicorp/terraform-plugin-testing/helper/acctest"	"github.com/hashicorp/terraform-plugin-testing/helper/resource"	"github.com/hashicorp/terraform-plugin-testing/terraform"	"github.com/hashicorp/terraform-provider-aws/internal/acctest"	"github.com/hashicorp/terraform-provider-aws/internal/conns"	tfglobalaccelerator"github.com/hashicorp/terraform-provider-aws/internal/service/globalaccelerator"	"github.com/hashicorp/terraform-provider-aws/internal/tfresource")funcTestAccGlobalAcceleratorListener_basic(t*testing.T){	ctx:=acctest.Context(t)	resourceName:="aws_globalaccelerator_listener.example"	rName:=sdkacctest.RandomWithPrefix(acctest.ResourcePrefix)	resource.ParallelTest(t,resource.TestCase{		PreCheck:(){acctest.PreCheck(ctx,t);testAccPreCheck(ctx,t)},		ErrorCheck:t.ErrorCheck(t,globalaccelerator.EndpointsID),		ProtoV5ProviderFactories:acctest.ProtoV5ProviderFactories,		CheckDestroy:testAccCheckListenerDestroy(ctx),		Steps:[]resource.TestStep{			{				Config:testAccListenerConfig_basic(rName),				Check:resource.ComposeTestCheckFunc(					testAccCheckListenerExists(ctx,resourceName),					resource.TestCheckResourceAttr(resourceName,"client_affinity","NONE"),					resource.TestCheckResourceAttr(resourceName,"protocol","TCP"),					resource.TestCheckResourceAttr(resourceName,"port_range.#","1"),					resource.TestCheckTypeSetElemNestedAttrs(resourceName,"port_range.*",map[string]string{						"from_port":"80",						"to_port":"81",					}),				),			},			{				ResourceName:ceName,				ImportState:				ImportStateVerify:true,			},		},	})}funcTestAccGlobalAcceleratorListener_disappears(t*testing.T){	ctx:=acctest.Context(t)	resourceName:="aws_globalaccelerator_listener.example"	rName:=sdkacctest.RandomWithPrefix(acctest.ResourcePrefix)	resource.ParallelTest(t,resource.TestCase{		PreCheck:(){acctest.PreCheck(ctx,t);testAccPreCheck(ctx,t)},		ErrorCheck:t.ErrorCheck(t,globalaccelerator.EndpointsID),		ProtoV5ProviderFactories:acctest.ProtoV5ProviderFactories,		CheckDestroy:testAccCheckListenerDestroy(ctx),		Steps:[]resource.TestStep{			{				Config:testAccListenerConfig_basic(rName),				Check:resource.ComposeTestCheckFunc(					testAccCheckListenerExists(ctx,resourceName),					acctest.CheckResourceDisappears(ctx,acctest.Provider,tfglobalaccelerator.ResourceListener(),resourceName),				),				ExpectNonEmptyPlan:true,			},		},	})}funcTestAccGlobalAcceleratorListener_update(t*testing.T){	ctx:=acctest.Context(t)	resourceName:="aws_globalaccelerator_listener.example"	rName:=sdkacctest.RandomWithPrefix(acctest.ResourcePrefix)	resource.ParallelTest(t,resource.TestCase{		PreCheck:(){acctest.PreCheck(ctx,t);testAccPreCheck(ctx,t)},		ErrorCheck:t.ErrorCheck(t,globalaccelerator.EndpointsID),		ProtoV5ProviderFactories:acctest.ProtoV5ProviderFactories,		CheckDestroy:testAccCheckListenerDestroy(ctx),		Steps:[]resource.TestStep{			{				Config:testAccListenerConfig_basic(rName),			},			{				Config:testAccListenerConfig_update(rName),				Check:resource.ComposeTestCheckFunc(					testAccCheckListenerExists(ctx,resourceName),					resource.TestCheckResourceAttr(resourceName,"client_affinity","SOURCE_IP"),					resource.TestCheckResourceAttr(resourceName,"protocol","UDP"),					resource.TestCheckResourceAttr(resourceName,"port_range.#","1"),					resource.TestCheckTypeSetElemNestedAttrs(resourceName,"port_range.*",map[string]string{						"from_port":"443",						"to_port":"444",					}),				),			},			{				ResourceName:ceName,				ImportState:				ImportStateVerify:true,			},		},	})}functestAccCheckListenerExists(ctxcontext.Context,nstring)resource.TestCheckFunc{	returnfunc(s*terraform.State)error{		conn:=acctest.Provider.Meta().(*conns.AWSClient).GlobalAcceleratorConn(ctx)		rs,ok:=s.RootModule().Resources[n]		if!ok{			returnfmt.Errorf("Notfound:%s",n)		}		ifrs.Primary.ID==""{			returnfmt.Errorf("NoGlobalAcceleratorListenerIDisset")		}		_,err:=tfglobalaccelerator.FindListenerByARN(ctx,conn,rs.Primary.ID)		returnerr	}}functestAccCheckListenerDestroy(ctxcontext.Context)resource.TestCheckFunc{	returnfunc(s*terraform.State)error{		conn:=acctest.Provider.Meta().(*conns.AWSClient).GlobalAcceleratorConn(ctx)		for_,rs:=ranges.RootModule().Resources{			ifrs.Type!="aws_globalaccelerator_listener"{				continue			}			_,err:=tfglobalaccelerator.FindListenerByARN(ctx,conn,rs.Primary.ID)			iftfresource.NotFound(err){				continue			}			iferr!=nil{				returnerr			}			returnfmt.Errorf("GlobalAcceleratorListener%sstillexists",rs.Primary.ID)		}		returnnil	}}functestAccListenerConfig_basic(rNamestring)string{	returnfmt.Sprintf(`resource"aws_globalaccelerator_accelerator""example"{name=%[1]qip_address_type="IPV4"enabled=false}resource"aws_globalaccelerator_listener""example"{accelerator_arn=aws_globalaccelerator_accelerator.example.idprotocolCP"port_range{from_port=80to_port=81}}`,rName)}functestAccListenerConfig_update(rNamestring)string{	returnfmt.Sprintf(`resource"aws_globalaccelerator_accelerator""example"{name=%[1]qip_address_type="IPV4"enabled=false}resource"aws_globalaccelerator_listener""example"{accelerator_arn=aws_globalaccelerator_accelerator.example.idclient_affinity="SOURCE_IP"protocolDP"port_range{from_port=443to_port=444}}`,rName)}